#include <iostream>
using namespace std;
int main()
{
    int allday, day = 0, i = 1, count = 0;
    cin >> allday;
    while (true)
    {
        if (day + i < allday)
        {
            count += i * i;
            day += i;
        }
        else if (day + i == allday)
        {
            count += i * i;
            day += i;
            break;
        }
        else
        {
            count += (allday - day) * i;
            day += allday - day;
            break;
        }
        i++;
    }
    cout<<count;
    return 0;
}
